window.__QUIZ_DATA__=[{"id":"theory>Physics>1999>PART I>1","subject":"Physics","year":"1999","type":"Theory","sub_label":"1","group":"CLOSENESS","topic":"LIGHT WAVES : DISPERSION OF WHITE LIGHT","question":"Explain  plane polarisation  of light.","images":["data:image/png;base64,"],"marking_scheme":"Polarisation of light occurs when the vibration of travelling light waves are perpendicular to the wave direction.  In this case vibration occurs in many different planes as shown below.    From the above, two polaroid Y and X are parallel to each other. OR is the allowed direction in the polaroid X while OS is that of Y. OR and OS are also parallel to the observer E as he sees the light the light in (i) above. But if X is kept still and Y is turned round slowly in its vertical plane. E sees the light passing through Y becoming less strong. No light passes through Y when its allowed in direction OS which is perpendicular to OR.  Note that phenomenon of light occurs in traversal wave but not longitudinal.","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART I>2","subject":"Physics","year":"1999","type":"Theory","sub_label":"2","group":"FINAL","topic":"PROJECTILE MOTION :","question":"A stone is projected horizontally from the top of a tower with a speed of 5 ms-1. It lands on the ground level at a horizontal distance of 20 m from the foot of the tower. Calculate the height of the tower.  [g = 10 ms-2]","images":["data:image/png;base64,"],"marking_scheme":"Sincetheparticleisprojectedhorizontally\u03b8=0o;Horizontalrange=uti.e.20=5t  t=205=4s  Tocalculatetheheightofthetower,Sy=usin\u03b8+12gt2  Butsin\u03b8=0  Sy=12gt2=12x10x42=5x16=80m","marks":"3","difficulty":"2"},{"id":"theory>Physics>1999>PART I>3","subject":"Physics","year":"1999","type":"Theory","sub_label":"3","group":"FINAL","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"In an electrolysis experiment, ammeter records a steady current of 1 A. The mass of copper deposited is 0.66 g in 30 minutes. Calculate the error in the ammeter reading reading.  [Electrochemical equivalent of copper = 0.00033 gC-1]","images":[],"marking_scheme":"ElectrochemicalequivalentofcopperZ=massQ  Q=quantityofelectricity;mass=0.66g  \u21d2Q=massZ=0.660.00033=2000C  Q=2000CButQ=It==>I=Qt=200030 minutes=200030 x 60=2018=1.11A  Error=Currentreading-Ammeterreading=1.11-1.00=0.11A","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART I>4>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"What is surface tension?","images":[],"marking_scheme":"Surface tension is that force of attraction that exist on the molecule of liquid at the surface due to the attractive force by the molecules below the surface.   It could be defined as the tangential force on the surface of the liquid. It is force per unit length on the surface of the liquid.","marks":"1","difficulty":"1"},{"id":"theory>Physics>1999>PART I>4>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"FLUID AT REST : PRESSURE IN FLUIDS","question":"State  two  methods by which the surface tension of a liquid can be reduced.","images":[],"marking_scheme":"- Introduction of impurities such as detergents, camphorcycopodium powder etc. to the surface of water.  - Increase the temperature due to heat also reduces surface tension","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART I>5>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"Define  Young's modulus","images":[],"marking_scheme":"Young modulus of a material is defined as as the ratio of the tensile stress of the material to that of the tensile strain of the same material.  Young'smodulusE=tensile stresstensile strain  Wheretensilestress=Forceperunitarea=FA  Tensilestrain=extensionperunitlength=eL  \u21d2E=F/Ae/L","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART I>5>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"State the physical quantity one has to measure in order to determine the Young's modulus of a wire.","images":[],"marking_scheme":"The physical quantities are:  - Force  - Cross-sectional area of the wire  - Temperature  - Extension of the wire  - Length of the wire","marks":"1","difficulty":"2"},{"id":"theory>Physics>1999>PART I>6>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"What is the principle upon which the lighting in a flourescent tube operate?","images":[],"marking_scheme":"The principle upon which the lighting in a flourescent tube operate is the principle of electrical discharge through a gas at very low pressure and very high voltage.","marks":"1","difficulty":"2"},{"id":"theory>Physics>1999>PART I>6>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : SOURCES OF LIGHT","question":"State  two  factors on which the colour of light from a flourescent tube depends","images":[],"marking_scheme":"- Type of electrode used to produce the light  - Pressure of the gas  - Nature of filament used  - Colour of the gas used","marks":"2","difficulty":"2"},{"id":"theory>Physics>1999>PART I>7>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"TYPES OF WAVES : WAVE MOTION","question":"List  two  types of waves, apart from light that can be plane polarised.","images":[],"marking_scheme":"- Gamma ray  - X-ray  - Radio wave","marks":"1","difficulty":"2"},{"id":"theory>Physics>1999>PART I>7>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"LIGHT WAVES : PLANE MIRROR","question":"State  two  applications of plane polarised light","images":[],"marking_scheme":"- In polaroids which are used in sunglasses to reduce the intensity of incident sunlight and to eliminate reflected light or glare  - It is also used in photo elastic stress analysis","marks":"2","difficulty":"2"},{"id":"theory>Physics>1999>PART I>8>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"HOOKE\u2019S LAW, YOUNG\u2019S MODULES AND WORK DONE IN SPRINGS AND STRING :","question":"State Hooke's law of elasticity.","images":[],"marking_scheme":"Hooke's law states that provided the elastic limit is not exceeded, the extension of a string is directly proportional to the load.","marks":"1","difficulty":"1"},{"id":"theory>Physics>1999>PART I>8>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"FINAL","topic":"FLUID AT REST : VOLUME, DENSITY AND RELATIVE DENSITY","question":"A spiral spring, loaded with a piece of metal, extends by 10.5 cm in air. When the metal is fully submerged in water, the spring extends by 6.8 cm. Calculate the relative density of the metal.  [Assume Hooke's law is obeyed]","images":[],"marking_scheme":"R.Dofthemetal=weight of the metal in airweight of equal volume of water  If u = volume of water = loss in weight when submerged in water but by Hooke's law  F \u03b1 e; F = ke where k is the constant of proportionality  If k = 1 unit; F = e where e = 10.5 cm; then u = 10.5 cm - 6.8 cm = 3.7 cm.  \u2234R.D=10.53.7=2.8","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART I>9>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"ELECTRIC FIELD : ELECTRIC CONDUCTION THROUGH MATERIALS","question":"Explain electrolysis","images":[],"marking_scheme":"Electrolysis is the process of decomposing certain liquids and solution into their component parts by the passage of electric current through the solution.   Example, if electrolysis of acidified water using Hoffman voltmeter principle. This shows that when current flows, hydrogen drifts towards the cathode where they receive electrons and form neutral hydrogen atoms which combines in pairs to form hydrogen molecules, at the same time the hydroxyl and the tetraoxosulphate(vi) ions move towards the anode.","marks":"1","difficulty":"2"},{"id":"theory>Physics>1999>PART I>9>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Classify the following substances as electrolytes and non-electrolytes. Sugar solution, paraffin, salt, solution, grape juice","images":[],"marking_scheme":"ElectrolytesNon-electrolytesSalt solutionSugar solutionGrape fruit juiceParaffin","marks":"2","difficulty":"2"},{"id":"theory>Physics>1999>PART I>10>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"STRUCTURE OF THE ATOM : ENERGY QUANTIZATION","question":"State Heisenberg's uncertainty principle","images":[],"marking_scheme":"Let x be the electron position and p be the momentum.  Heisenberg's uncertainty principle states that if \u2206x is the uncertainty in measuring x, and \u2206p is the uncertainty in measuring p, then their product is equal to or greater than h, (the planck's constant) i.e. \u2206x.\u2206p \u2265 h  OR  Heisenberg's uncertainty principle states it is impossible to know accurately the exact position and momentum of a particle simultaneously.","marks":"1","difficulty":"3"},{"id":"theory>Physics>1999>PART I>10>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"WAVE-PARTICLE PARADOX : DUALITY OF MATTER","question":"Mention  two  phenomena that can only be explained in terms of the particulate nature of light.","images":[],"marking_scheme":"- Photon  - Diffraction rings","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART II>1>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"EQUILIBRIUM OF FORCES : CONDITIONS FOR EQUILIBRIUM OF RIGID BODIES UNDER THE ACTION OF PARALLEL AND NON-PARALLEL FORCES","question":"State the conditions for the equilibrium of a rigid body acted upon by parallel forces.","images":[],"marking_scheme":"- The algebraic sum of the moments acting on the body in any direction must be zero  - Sum of the upward forces must be equal to the downward force  - The algebraic sum of the moments of all the forces acting about any point must be zero  - The sum of clockwise moment about any point must be equal to the sum of anticlockwise moment about the same point","marks":"2","difficulty":"2"},{"id":"theory>Physics>1999>PART II>1>b>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"Describe an experiment, using the principle of moments to determine the mass of a metre.","images":["data:image/png;base64,"],"marking_scheme":"Aim:  To determine the mass of a metre rule.  Apparatus: A known mass M, metre rule, a pivot, string    AB is a metre rule first balanced freely by pivot and its centre of mass (m) is known. A load of mass M is now placed one end of the metre rule so that its centre of gravity change and and the distance of difference x. The distance of the supported load is y.  Since moment is the product of force and the perpendicular distance and the clockwise moment is equal to anticlockwise moment  \u21d2Mxy=mxx;m=Myx  Note x and y can be read in the metre rule and mass M is already known.","marks":"10","difficulty":"2"},{"id":"theory>Physics>1999>PART II>1>b>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"EQUILIBRIUM OF FORCES : PRINCIPLE OF MOMENTS","question":"State  two  precautions necessary to ensure accurate results.","images":[],"marking_scheme":"- The attached mass was carefully placed at notable position to the point of pivotion and allowed to be in equilibrium position with the weight of the metre rule before taking the reading.  - I avoided error due to parallax when the readings from the metre rule  - I also avoided drought which can affect my reading i.e. all interference factors like wind, restlessness etc. were kept at constant level","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART II>1>c>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A bullet of mass 120 g is fired horizontally into a fixed wooden block with a speed of 20 ms-1. The bullet is brought to rest in the block in 0.1 s by a constant resistance. Calculate the:    magnitude of the resistance","images":["data:image/png;base64,"],"marking_scheme":"mass=120g=0.12kg;u=20ms-1;t=0.1s;v=0    Resistanceofwood=momentum exerted to the wood by the bullettime  =0.12 x 200.1=2.40.1=24N","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART II>1>c>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"NEWTON\u2019S LAWS OF MOTION : SECOND LAW","question":"A bullet of mass 120 g is fired horizontally into a fixed wooden block with a speed of 20 ms-1. The bullet is brought to rest in the block in 0.1 s by a constant resistance. Calculate the:  distance, moved by the bullet in the wood","images":[],"marking_scheme":"Tocalculatethedistance=v2=u2+2as  a=v - ut=0 - 200.1=-200.1=-200ms2  \u21d20=202-2x200xs  =0=400-400s  =400s=400  \u2234s=400400=1m","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART II>2>a>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"WORK, ENERGY AND POWER : CONCEPT OF WORK","question":"Explain    Work","images":[],"marking_scheme":"Work is said to be done whenever a force moves a body through a distance in the direction of force. Workdone is equal to the product of the force and the distance moved in the direction of the force.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART II>2>a>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"WORK, ENERGY AND POWER : CONCEPT OF POWER","question":"Explain  Power","images":[],"marking_scheme":"Power is defined as the rate of doing the work. It means the rate of transfer of energy.","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART II>2>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"","topic":"MACHINES :","question":"Show that the efficiency \u03b5, the force ratio M.A and the velocity ratio V.R of a machine is related by the equation:  \u03b5=M.AV.Rx100%","images":[],"marking_scheme":"Toshowthat\u03b5=M.AV.Rx100%  Bydefinition\u03b5=Work outputWork inputx100%  Sincework=forcexdistance  Work outputWork input=Load x distance moved by the loadEffort x distance moved by effort  Ifdistancemovedbyload=yandLoad=L  Ifdistancemovedbyeffort=xandEffort=E  \u21d2\u03b5=LyExx100%  WhereLE=M.Aandxy=V.R  \u21d2\u03b5=LE\u00f7xyx100%=M.A\u00f7V.Rx100%  \u2234\u03b5=M.AV.Rx100%(QED)","marks":"5","difficulty":"2"},{"id":"theory>Physics>1999>PART II>2>c>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"FINAL","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"An inclined plane of angle 15o is used to raise a load of 4500 N through a height of 2 m. If the plane is 75% efficient, calculate    velocity ratio of the plane","images":["data:image/png;base64,"],"marking_scheme":"Distancemovedbytheeffort=x  \u03b5=75%;L=4500N;\u03b8=15o;h=2m  sin15o=2x;x=2sin 15o=7.73m  \u21d2V.R=Distance moved by effortDistance moved by load=7.732=3.86","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART II>2>c>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"WORK, ENERGY AND POWER : WORK DONE IN A GRAVITATIONAL FIELD","question":"An inclined plane of angle 15o is used to raise a load of 4500 N through a height of 2 m. If the plane is 75% efficient, calculate  work done on the load","images":[],"marking_scheme":"\u03b5=M.AV.Rx100%  \u21d275%=M.A3.86x100%  =75100=M.A3.86  =0.75=M.A3.86  \u2234M.A=0.75x3.86=2.9\u22433  M.A=LE  =3=4500E  =3E=4500  \u2234E=45003=1500N  Workdoneontheload=Effortxdistancemovedbytheeffort=1500x7.73=11,595J","marks":"5","difficulty":"3"},{"id":"theory>Physics>1999>PART II>2>c>iii","subject":"Physics","year":"1999","type":"Theory","sub_label":"iii","group":"CLOSENESS","topic":"CONCEPTS OF MATTER : CONCEPTS OF MATTER","question":"Explain Charles' law using the kinetic theory of matter.","images":[],"marking_scheme":"Charles' law states that the volume of an ideal gas is directly proportional to the absolute temperature at constant pressure  FromCharles'law==>V1T1=V2T2wherepressureisconstant   Explanation:   According to Charles' law, gases will expand when heated. The temperature of a gas is really a measure of the average kinetic energy of the particles. As the kinetic energy increases, the particles will move faster and want to make more collisions with the container. However, remember that in order for the law to apply, the pressure must remain constant. The only way to do this is by increasing the volume.","marks":"3","difficulty":"2"},{"id":"theory>Physics>1999>PART II>3>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"CLOSENESS","topic":"PROPERTIES OF WAVES : SUPERPOSITION","question":"State  three  properties of waves.","images":[],"marking_scheme":"- Reflection  - Refraction  - Diffraction","marks":"3","difficulty":"1"},{"id":"theory>Physics>1999>PART II>3>b>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"Describe with the aid of labelled diagram an experiment to show how the frequency of the note emitted by a vibrating string depends on the tension in the string.","images":["data:image/png;base64,"],"marking_scheme":"The length of the string is kept constant throughout the experiment but the tension of the string is altered simply by altering the weight (W) suspended. The thickness of the string of the string is also kept constant in other to ensure that the mass per unit length is constant throughout the experiment. When a tunning fork of known frequency and the string are set into vibration so that they both vibrate with uniform frequency, the frequency of the fork is taken and recorded. Also the tension which is proportional to the weight of the load suspended is also recorded. The experiment is repeated for at least 5 times by varying the mass and the fork used as a source of vibration. The values of f and T are taken and recorded. In each case the \u221aT is also taken.  The graph of f is plotted against \u221aT a straight line graph passing through the origin is obtained  \u2234 F \u03b1 \u221aT","marks":"10","difficulty":"2"},{"id":"theory>Physics>1999>PART II>3>b>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"SOUND WAVES : VIBRATION IN STRINGS","question":"State  two  precautions necessary to ensure accurate result","images":[],"marking_scheme":"- The length of the string should be kept constant throughout the experiment  - The thickness of the string should also be kept constant throughout the experiment","marks":"2","difficulty":"1"},{"id":"theory>Physics>1999>PART II>3>c","subject":"Physics","year":"1999","type":"Theory","sub_label":"c","group":"","topic":"LIGHT WAVES : REFLECTION OF LIGHT AT CURVED SURFACES","question":"Draw a ray diagram showing how a virtual image of an object is formed by a concave mirror.","images":["data:image/png;base64,"],"marking_scheme":"A virtual but magnified image can be formed in a concave mirror by placing the object between principal focus and the mirror.","marks":"5","difficulty":"2"},{"id":"theory>Physics>1999>PART II>4>a","subject":"Physics","year":"1999","type":"Theory","sub_label":"a","group":"","topic":"MAGNETIC FIELD : CURRENT-CARRYING CONDUCTOR IN A MAGNETIC FIELD","question":"Sketch the magnetic flux pattern around a long, straight, current carrying wire.","images":["data:image/png;base64,"],"marking_scheme":"[Magnetic field flux due to long straight current-carrying wire]","marks":"4","difficulty":"2"},{"id":"theory>Physics>1999>PART II>4>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"ELECTRIC FIELD : CURRENT ELECTRICITY","question":"State  two  methods by which the sensitivity of a moving coil galvanometer can be increased.","images":[],"marking_scheme":"- The field B must be stronger  - Number of turns N and the cross-sectional area A of the coil must be considerably great  - The spring constant C which depends on the elasticity under twisting forces must be very low","marks":"2","difficulty":"2"},{"id":"theory>Physics>1999>PART II>4>c>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"","topic":"SIMPLE A.C. CIRCUITS : SERIES CIRCUIT CONTAINING RESISTOR, INDUCTOR AND CAPACITOR","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz    Draw the circuit diagram of the arrangement","images":["data:image/png;base64,"],"marking_scheme":"","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART II>4>c>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"FINAL","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz  Calculate the capacitive reactance","images":[],"marking_scheme":"R=100\u03a9;L=3H;C=4\u03bcF;V=100V;f=160\u03c0Hz  XC=12\u03c0fC=12\u03c0 x 160/\u03c0 x 4 x 10-6=18 x 160 x 10-6=1061280  \u2234XC=781.25\u03a9","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART II>4>c>iii","subject":"Physics","year":"1999","type":"Theory","sub_label":"iii","group":"FINAL","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz  Calculate the inductive reactance","images":[],"marking_scheme":"XL=2\u03c0fL=2x\u03c0x160\u03c0x3=960\u03a9","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART II>4>c>iv","subject":"Physics","year":"1999","type":"Theory","sub_label":"iv","group":"CLOSENESS","topic":"SIMPLE A.C. CIRCUITS : REACTANCE AND IMPEDANCE","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz  Calculate the impedance of the circuit","images":[],"marking_scheme":"Z = \u221a[(XL - XC)2 + R2]    Z = \u221a[960 - 781.25)2 + 1002]    Z = \u221a(31951.6 + 10000)    Z = \u221a41951.6    \u2234 Z = 204.82 \u03a9","marks":"3","difficulty":"3"},{"id":"theory>Physics>1999>PART II>4>c>v","subject":"Physics","year":"1999","type":"Theory","sub_label":"v","group":"FINAL","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz  Calculate the current in the circuit","images":[],"marking_scheme":"I=VZ=100204.82=0.488A","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART II>4>c>vi","subject":"Physics","year":"1999","type":"Theory","sub_label":"vi","group":"FINAL","topic":"SIMPLE A.C. CIRCUITS : POWER","question":"A series RLC circuit comprises a 100-\u03a9 resistor a 3-H inductor and a 4-\u03bcF capacitor. The a.c source of the circuit has an e.m.f of 100 v and frequency of 160/\u03c0 Hz  Calculate the average power dissipated in the circuit","images":[],"marking_scheme":"Power = IV = 0.488 x 100 = 48.8 W","marks":"2","difficulty":"3"},{"id":"theory>Physics>1999>PART II>5>a>i","subject":"Physics","year":"1999","type":"Theory","sub_label":"i","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Explain    fusion","images":[],"marking_scheme":"Nuclear fusion is a process in which light nuclides combine to give heavier nuclide with the release of energy. In this process mass is lost. e.g fusion of two nuclides of Hydrogen.","marks":"3","difficulty":"1"},{"id":"theory>Physics>1999>PART II>5>a>ii","subject":"Physics","year":"1999","type":"Theory","sub_label":"ii","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"Explain  fission","images":["data:image/png;base64,"],"marking_scheme":"Nuclear fission is a process in which a nuclear bombardment of the nucleus of a heavy nuclide by particles such as neutron results in splitting of the molecules into two smaller nuclei with the release of energy e.g bombardment of uranium-235 with neutrons which later splits.    [Energy is released in the equation above]","marks":"3","difficulty":"1"},{"id":"theory>Physics>1999>PART II>5>b","subject":"Physics","year":"1999","type":"Theory","sub_label":"b","group":"CLOSENESS","topic":"STRUCTURE OF THE NUCLEUS : FUSION AND FISSION","question":"State  three  advantages of fusion over fission in the generation of power","images":[],"marking_scheme":"- Fusion is easily achieved with the lightest elements so that nuclear repulsion is easily overcome as nuclei approach each other.  - The by products of fusion are not as dangerous as fission's  - There is no upper limit to the mass of hydrogen that can be exploded, so very large energy can be obtained.","marks":"6","difficulty":"2"},{"id":"theory>Physics>1999>PART II>5>c","subject":"Physics","year":"1999","type":"Theory","sub_label":"c","group":"","topic":"STRUCTURE OF THE NUCLEUS : COMPOSITION OF THE NUCLEUS","question":"Calculate, in joules, the binding energy for 5927Co  [Atomic mass of 5927Co = 58.9332 u]  [Mass of proton = 1.00783 u]  [Mass of neutron = 1.00867 u]  [Unified Atomic Mass u = 931 MeV]  [1 eV = 1.6 x 10-19 J]","images":[],"marking_scheme":"5927Co = 32 + 2727Co  Number of proton = 27; No of neutrons = 32  \u2234 Energy in proton = 27(1.00783) = 27.21141 u  Energy in neutron = 32(1.00867) = 32.27744 u  Energy in the atom = 58.9332 u  Binding energy (B.E) = E.P + E.N - E.A = 27.21141 u + 32.27744 u - 58.9332 u   B.E = 59.48885 u - 58.9332 u = 0.55565 u  = 0.55565 x  931 MeV = 517.3 MeV  = 517.3 x 106 x 1.6 x 10-19  \u2234 B.E = 8.28 x 10-11 J","marks":"8","difficulty":"3"}];